public record ThemeInfo(ThemeMode Theme = ThemeMode.Light, string AccentColor = "#0d6efd");

using Microsoft.AspNetCore.Components;

namespace sv_6636c95226134fdeadf5494a0c32808a.Services;

/// <summary>
/// Scoped (per-circuit) service that bridges the singleton <see cref="ThemeStore"/>
/// with a <see cref="CascadingValueSource{ThemeInfo}"/> so that every component in the
/// circuit receives live updates via [CascadingParameter].
///
/// When another circuit in the same browser session changes the theme, the singleton
/// store fires its event, this service receives it, and pushes the new value into the
/// cascading source — causing all subscribers in THIS circuit to re-render.
/// </summary>
public sealed class ThemeState : IDisposable
{
    private readonly ThemeStore _store;
    private readonly string _sessionId;

    /// <summary>
    /// The cascading value source owned by this circuit. Registered in DI via
    /// <c>AddCascadingValue</c> so that any component can consume it with
    /// <c>[CascadingParameter]</c>.
    /// </summary>
    public CascadingValueSource<ThemeInfo> Source { get; }

    public ThemeInfo Current => _store.Get(_sessionId);

    public ThemeState(ThemeStore store, IHttpContextAccessor httpContextAccessor)
    {
        _store = store;
        _sessionId = httpContextAccessor.HttpContext?.Items["ThemeSessionId"] as string
                     ?? "default";

        Source = new CascadingValueSource<ThemeInfo>(_store.Get(_sessionId), isFixed: false);
        _store.OnChanged += HandleStoreChanged;
    }

    public async Task SetThemeAsync(ThemeMode mode)
    {
        var updated = Current with { Theme = mode };
        _store.Set(_sessionId, updated);
    }

    public async Task SetAccentColorAsync(string color)
    {
        var updated = Current with { AccentColor = color };
        _store.Set(_sessionId, updated);
    }

    private async void HandleStoreChanged(string sessionId, ThemeInfo theme)
    {
        if (sessionId != _sessionId) return;

        try
        {
            await Source.NotifyChangedAsync(theme);
        }
        catch (ObjectDisposedException)
        {
            // Circuit was torn down — safe to ignore.
        }
    }

    public void Dispose()
    {
        _store.OnChanged -= HandleStoreChanged;
    }
}

