arguments.new_str:
using sv_6636c95226134fdeadf5494a0c32808a;
using sv_6636c95226134fdeadf5494a0c32808a.Components;
using sv_6636c95226134fdeadf5494a0c32808a.Services;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container.
builder.Services.AddRazorComponents()
    .AddInteractiveServerComponents();

builder.Services.AddHttpContextAccessor();
builder.Services.AddSingleton<ThemeStore>();
builder.Services.AddScoped<ThemeState>();

// Register the CascadingValueSource via the scoped ThemeState so every circuit
// automatically subscribes to cross-circuit theme changes.
builder.Services.AddCascadingValue(sp => sp.GetRequiredService<ThemeState>().Source);

var app = builder.Build();

// Configure the HTTP request pipeline.
if (!app.Environment.IsDevelopment())
{
    app.UseExceptionHandler("/Error", createScopeForErrors: true);
}
app.UseStatusCodePagesWithReExecute("/not-found", createScopeForStatusCodePages: true);

// Assign a stable session ID cookie so all circuits from the same browser
// share theme state. Read by ThemeState via HttpContext.Items.
app.Use(async (context, next) =>
{
    if (!context.Request.Cookies.TryGetValue("ThemeSessionId", out var sessionId))
    {
        sessionId = Guid.NewGuid().ToString();
        context.Response.Cookies.Append("ThemeSessionId", sessionId, new CookieOptions
        {
            HttpOnly = true,
            SameSite = SameSiteMode.Strict,
            Expires = DateTimeOffset.UtcNow.AddYears(1)
        });
    }
    context.Items["ThemeSessionId"] = sessionId;
    await next();
});

app.UseAntiforgery();

app.MapStaticAssets();
app.MapRazorComponents<App>()
    .AddInteractiveServerRenderMode();

app.Run();

