@rendermode InteractiveServer
@inject ThemeState ThemeState

<span class="theme-indicator d-inline-flex align-items-center gap-1"
      title="Current theme: @(Theme?.Theme) — Accent: @(Theme?.AccentColor)">
    <span>@GetThemeIcon(Theme?.Theme ?? ThemeMode.Light)</span>
    <span class="badge" style="background-color: @(Theme?.AccentColor ?? "#0d6efd");">
        @(Theme?.Theme.ToString() ?? "Light")
    </span>
</span>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }

    private static string GetThemeIcon(ThemeMode mode) => mode switch
    {
        ThemeMode.Dark   => "🌙",
        ThemeMode.System => "💻",
        _                => "☀️"
    };
}

@page "/settings"
@rendermode InteractiveServer
@inject ThemeState ThemeState

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="mb-3">
    <label class="form-label fw-bold">Theme</label>
    <div class="btn-group" role="group">
        @foreach (var mode in Enum.GetValues<ThemeMode>())
        {
            <button class="btn @(Theme?.Theme == mode ? "btn-primary" : "btn-outline-primary")"
                    @onclick="() => SetTheme(mode)">
                @mode
            </button>
        }
    </div>
</div>

<div class="mb-3">
